#include <stdio.h>
#include <stdlib.h>
#include <errno.h>
#include <string.h>

int main(void) {
    FILE *file;

    /* Reset errno before a library call to avoid stale states */
    errno = 0;

    file = fopen("critical_system_config.dat", "r");
    if (file == NULL) {
        /* Print descriptive error to standard error stream */
        perror("System Error when opening config file");

        /* Alternatively, log using strerror for customized output */
        fprintf(stderr, "Diagnostic Details: (code %d) -> %s\n", errno, strerror(errno));

        /* Exit gracefully with a failure code */
        exit(EXIT_FAILURE);
    }

    /* Perform work if successfully opened */
    printf("File opened successfully!\n");
    fclose(file);
    return EXIT_SUCCESS;
}

