#include <stdio.h>
#include <stdlib.h>
#include <assert.h>

#define MAX_BUFFER_SIZE 1024

void process_payload(const int *payload, size_t size) {
    /* Developer Invariant validation: Pointers must never be null and sizes must stay bounded */
    assert(payload != NULL);
    assert(size > 0 && size <= MAX_BUFFER_SIZE);

    printf("Processing payload of size %zu...\n", size);
}

int main(void) {
    int *data = NULL;
    size_t data_size = 500;

    /* Simulating a dynamic allocation scenario */
    data = (int *)malloc(data_size * sizeof(int));

    /* Fallback handler: Allocation failures at runtime are handled with exit or abort, not asserts */
    if (data == NULL) {
        fprintf(stderr, "CRITICAL: Out of memory. Aborting execution...\n");
        abort();
    }

    /* Run operations under protected developer conditions */
    process_payload(data, data_size);

    free(data);
    return 0;
}

