#include <stdio.h>
#include <errno.h>
#include <assert.h>

int safe_divide(int numerator, int denominator, int *result) {
    /* Assert that the pointer to save result is valid (Developer Error if null) */
    assert(result != NULL);

    /* Handle Division by zero as a Runtime Error using errno */
    if (denominator == 0) {
        errno = EDOM; /* Domain error code */
        return -1;
    }

    *result = numerator / denominator;
    return 0;
}

questionsAndAnswers.question:
Identify and correct the bug in the following error diagnostic snippet: 

FILE *f = fopen("data.txt", "r");
if (f == NULL) {
    printf("Log: fopen failed.\n");
    if (errno == ENOENT) {
        printf("File does not exist.\n");
    }
}

questionsAndAnswers.answer:
The bug is that printf() is called between the failed fopen() call and checking the value of errno. printf() is itself a system operation that can modify the value of errno, potentially overwriting the error code set by fopen(). The correct implementation is:

FILE *f = fopen("data.txt", "r");
if (f == NULL) {
    int saved_err = errno; /* Instantly capture the error code */
    printf("Log: fopen failed.\n");
    if (saved_err == ENOENT) {
        printf("File does not exist.\n");
    }
}

questionsAndAnswers.question:
Identify and fix the resource leak bug in this function on early failure exit: 

int process_log(const char *path) {
    FILE *file = fopen(path, "r");
    if (!file) return -1;
    char *buffer = malloc(1024);
    if (!buffer) return -1;
    if (fgets(buffer, 1024, file) == NULL) {
        return -1;
    }
    free(buffer);
    fclose(file);
    return 0;
}

questionsAndAnswers.answer:
The bug is that if fgets() fails, the function returns -1 immediately, failing to free the allocated 'buffer' and failing to close the open 'file' descriptor. This causes memory and file handle resource leaks. The correct approach uses structured cleanup labels:

int process_log(const char *path) {
    FILE *file = fopen(path, "r");
    if (!file) return -1;

    char *buffer = malloc(1024);
    if (!buffer) {
        fclose(file);
        return -1;
    }

    int status = 0;
    if (fgets(buffer, 1024, file) == NULL) {
        status = -1;
    }

    free(buffer);
    fclose(file);
    return status;
}

#include <stdio.h>
#include <stdlib.h>
#include <errno.h>
#include <limits.h>

long robust_atoi(const char *str, int *valid) {
    char *endptr;
    errno = 0;
    *valid = 1;

    long val = strtol(str, &endptr, 10);

    /* Check for overflow/underflow or standard range validation errors */
    if ((errno == ERANGE && (val == LONG_MAX || val == LONG_MIN)) || (errno != 0 && val == 0)) {
        *valid = 0;
        return 0;
    }
    /* If no digits were found, it's an error */
    if (endptr == str) {
        *valid = 0;
        return 0;
    }
    return val;
}

#include <stdio.h>
#include <stdlib.h>
#include <assert.h>

typedef struct {
    int *data;
    size_t size;
    size_t capacity;
} IntArray;

IntArray* create_array(size_t init_capacity) {
    assert(init_capacity > 0);
    IntArray *arr = malloc(sizeof(IntArray));
    if (!arr) {
        perror("Failed to allocate array structure");
        exit(EXIT_FAILURE);
    }
    arr->data = malloc(init_capacity * sizeof(int));
    if (!arr->data) {
        free(arr);
        perror("Failed to allocate array buffer");
        exit(EXIT_FAILURE);
    }
    arr->size = 0;
    arr->capacity = init_capacity;
    return arr;
}

void write_at(IntArray *arr, size_t index, int value) {
    assert(arr != NULL);
    /* Array index safety validation using assertions (Developer API contracts) */
    assert(index < arr->capacity);

    arr->data[index] = value;
    if (index >= arr->size) {
        arr->size = index + 1;
    }
}

